function ModelDivineWeaponFight:DescendsInfoResp(pb)
    if self.curBarrierId ~= 0 and self.curBarrierId ~= pb.obj.barrierId then
        self:SetIsUpdateBarrier(true)
    end
    self.curChapterId = pb.obj.chapterId
    self.curBarrierId = pb.obj.barrierId
    self.freeSweepNum = pb.obj.freeSweepNum
    self.buySweepNum = pb.obj.buySweepNum
    self.failTime = pb.obj.failTime
    self.chapterInfo = {}
    for _, v in ipairs(pb.obj.chapterInfos) do
        self:HandleChapterInfo(v)
    end
    FireEvent("DescendsInfoResp")
end

