function ModelDivineWeaponFight:HandleChapterInfo(data)
    local notFullStarBarriers = {}
    for _, v2 in ipairs(data.notFullStarBarriers) do
        local star = { false, false, false }
        for _, v in ipairs(v2.star) do
            star[v] = true
        end
        notFullStarBarriers[v2.barrierId] = {
            barrierId = v2.barrierId,
            star = star
        }
    end
    self.chapterInfo[data.chapterId] = {
        chapterId = data.chapterId,
        starChest = data.starChest or {},
        starNum = data.starNum,
        isOpen = data.isOpen,
        notFullStarBarriers = notFullStarBarriers
    }
end

