function ModelDivineWeaponFight:GetBarrierByChapter(chapter)
    if not self.barrierCfgInfo then
        self.barrierCfgInfo = {}
        for _, v in pairs(GameTable.DescendsBarrierRef) do
            if not self.barrierCfgInfo[v.chapterId] then
                self.barrierCfgInfo[v.chapterId] = {}
            end
            table.insert(self.barrierCfgInfo[v.chapterId], v)
        end
        for _, v in ipairs(self.barrierCfgInfo) do
            table.sort(v, function(a, b)
                return a.refId < b.refId
            end)
        end
    end
    return self.barrierCfgInfo[chapter]
end

