function ModelDivineWeaponFight:GetStarStrByCond(cond)
    local data = string.split(cond, "=")
    local str = starCond[tonumber(data[1])]
    data[2] = tonumber(data[1]) == 3 and data[2] * 100 or data[2]
    return str and string.replace(str, data[2]) or ""
end

