function ModelDivineWeaponFight:GetChapterRedPointById(id)
    local chapterInfo = self:GetChapterInfoById(id)
    if table.isempty(chapterInfo) then
        return false
    end
    local chapterCfg = self:GetChapterCfgById(id)
    local starNum = chapterInfo.starNum or 0
    local isGetNum = #chapterInfo.starChest
    local starProgress = string.split(chapterCfg.starProgress, "=")
    for i, v in ipairs(starProgress) do
        local num = tonumber(v)
		if starNum >= num and isGetNum < i then
			return true
		end
    end
    return false
end

function ModelDivineWeaponFight:GetChapterSweepRedPoint(id)
    local allFreeSweepNum = self:GetAllFreeSweepNum()
    if self.freeSweepNum >= allFreeSweepNum then
        return false
    end
    local chapterInfo = self:GetChapterInfoById(id)
    if table.isempty(chapterInfo) then
        return false
    end
    local chapterCfg = self:GetChapterCfgById(id)
    local starNum = chapterInfo.starNum or 0
    local starInfo = string.split(chapterCfg.starProgress, "=")
    local isFullStar = starNum == tonumber(starInfo[#starInfo])
    return isFullStar
end

function ModelDivineWeaponFight:GetSweepItemByTimes(chapter, times)
    local chapterCfg = self:GetChapterCfgById(chapter)
    local sweepData = string.split(chapterCfg.consume, ",")
    return LxDataHelper.ParseItem_4(sweepData[times])
end

